// 对全文公式进行居中排版，编号右对齐
var doc = Application.ActiveDocument;
var paragraphs = doc.Content.Paragraphs;
var i, p, text, lines, lineNum = paragraphs.Count;

for (i = 1; i <= lineNum; i++) {
    p = paragraphs.Item(i);
    text = p.Range.Text;

    // 检测是否包含公式标记（如 $$ ... $$）
    if (text.indexOf('$$') !== -1) {
        // 设置段落居中对齐
        p.Range.ParaFormat.Alignment = 1; // 1 = 两端对齐/居中效果

        // 如果文本中有编号标记，尝试处理右对齐
        if (text.indexOf('\\rightline') > -1 || text.indexOf('右对齐') > -1) {
            p.Range.ParaFormat.KeepTogetherWithNext = false;
        }
    }
}

// 查找所有数学公式并应用特殊格式
var shapes = doc.Shapes;
var j, shapeCount = shapes.Count;
for (j = 0; j < shapeCount; j++) {
    var shape = shapes.Item(j);
    if (shape.Type === 13) { // 13 通常代表公式形状
        shape.Locked = false;
        shape.Select();
        // 设置公式框水平居中
        shape.Left = (doc.PageSetup.PaperSize == 1) ? 180 : 200; 
    }
}

"公式居中与编号右对齐排版已完成"
